package main

import (
	"os"

	sandboxv1alpha1 "github.com/volcano-sh/agentcube/pkg/apis/sandbox/v1alpha1"
	agentdpkg "github.com/volcano-sh/agentcube/pkg/agentd"
	"k8s.io/apimachinery/pkg/runtime"
	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client/config"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/manager/signals"
)

func init() {
	scheme := runtime.NewScheme()
	utilruntime.Must(sandboxv1alpha1.AddToScheme(scheme))
}

func main() {
	klog.InitFlags(nil)

	cfg, err := config.GetConfig()
	if err != nil {
		klog.Fatalf("Failed to get config: %v", err)
	}

	mgr, err := manager.New(cfg, manager.Options{
		MetricsBindAddress:     "0",
		HealthProbeBindAddress: "0",
		Scheme:                 runtime.NewScheme(),
	})
	if err != nil {
		klog.Fatalf("Failed to create manager: %v", err)
	}

	utilruntime.Must(sandboxv1alpha1.AddToScheme(mgr.GetScheme()))

	reconciler := &agentdpkg.Reconciler{
		Client: mgr.GetClient(),
		Scheme: mgr.GetScheme(),
	}

	if err := reconciler.SetupWithManager(mgr); err != nil {
		klog.Fatalf("Failed to setup reconciler: %v", err)
	}

	ctx := signals.SetupSignalHandler()

	klog.Info("Starting agentd")
	if err := mgr.Start(ctx); err != nil {
		klog.Fatalf("Manager error: %v", err)
	}
}

