package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                  *redis.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func NewValkeyStore() Store {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}

	password := os.Getenv("VALKEY_PASSWORD")

	cli := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	return s.cli.Ping(ctx).Err()
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionPrefix + sessionID
	data, err := s.cli.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := s.cli.Pipeline()
	pipe.Set(ctx, key, data, 0)
	pipe.ZAdd(ctx, s.expiryIndexKey, redis.Z{Score: float64(sandbox.ExpiresAt.Unix()), Member: sessionID})
	pipe.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{Score: float64(time.Now().Unix()), Member: sessionID})

	_, err = pipe.Exec(ctx)
	return err
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sessionID string, sandbox *types.SandboxInfo) error {
	key := s.sessionPrefix + sessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	result, err := s.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !result {
		return ErrNotFound
	}

	return nil
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionPrefix + sessionID

	pipe := s.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, s.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, s.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.expiryIndexKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.lastActivityIndexKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    fmt.Sprintf("%d", before.Unix()),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	key := s.sessionPrefix + sessionID
	exists, err := s.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}

	if exists != 1 {
		return ErrNotFound
	}

	return s.cli.ZAdd(ctx, s.lastActivityIndexKey, redis.Z{Score: float64(time.Now().Unix()), Member: sessionID}).Err()
}

func (s *valkeyStore) Close() error {
	return s.cli.Close()
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
